// Extract binary file data and form fields
const formData = $input.first().json;
const clientName = formData['Client Name'] || 'Client';
const thresholdOption = formData['Confidence Threshold'] || '0.4 - Broad (Recommended)';
const threshold = thresholdOption.split(' - ')[0] || '0.4';

// Get the uploaded file binary key
const binaryKey = Object.keys($input.first().binary || {})[0];
if (!binaryKey) {
  throw new Error('No file uploaded. Please upload an Excel file.');
}
const binaryMeta = $input.first().binary[binaryKey];

// Use n8n helper to get actual binary buffer (works with filesystem storage mode)
const buffer = await this.helpers.getBinaryDataBuffer(0, binaryKey);
const fileBase64 = buffer.toString('base64');

if (fileBase64.length < 100) {
  throw new Error('File data too small (' + fileBase64.length + ' chars). Upload may have failed.');
}

return [{
  json: {
    fileBase64: fileBase64,
    fileName: binaryMeta.fileName || 'upload.xlsx',
    threshold: threshold,
    limit: 3,
    client_name: clientName
  }
}];

// Collect all matched items and format a Telegram approval message
const items = $input.all();
const clientName = items[0]?.json?.client_name || 'Client';

// Construct the Wait node resume URLs FIRST
let baseUrl = '';
try { baseUrl = $env.WEBHOOK_URL || ''; } catch(e) { baseUrl = ''; }
if (!baseUrl) {
  baseUrl = 'http://localhost:5678';
}
baseUrl = baseUrl.replace(/\/$/, '');

const executionId = $execution.id;
const approveUrl = baseUrl + '/webhook-waiting/' + executionId + '?action=approve';
const rejectUrl = baseUrl + '/webhook-waiting/' + executionId + '?action=reject';

// Build the approval message with all matched products
let message = '\u2705 <b>RFP Product Matches Ready for Approval</b>\n\n';
message += '<b>Client:</b> ' + clientName + '\n';
message += '<b>Matched Products:</b> ' + items.length + '\n\n';

items.forEach((item, i) => {
  const d = item.json;
  const confPct = (d.confidence * 100).toFixed(1);
  const src = d.match_source === 'image' ? ' [IMG]' : ' [TXT]';
  message += '<b>' + (i + 1) + '. ' + d.product_name + '</b> (' + d.brand + ')' + src + '\n';
  message += '   RFP: "' + d.query + '"\n';
  message += '   Confidence: ' + confPct + '% | Qty: ' + d.quantity + '\n';
  if (d.location) message += '   Location: ' + d.location + '\n';
  if (d.dimensions) message += '   Dims: ' + d.dimensions + '\n';
  if (d.source_url) message += '   \uD83D\uDD17 <a href="' + d.source_url + '">View Product</a>\n';
  message += '\n';
});

message += '\n\u2705 <b>To APPROVE:</b> Open this link in your browser:\n' + approveUrl + '\n\n\u274C <b>To REJECT:</b> Open this link:\n' + rejectUrl;

return [{
  json: {
    message: message,
    approveUrl: approveUrl,
    rejectUrl: rejectUrl,
    itemCount: items.length,
    clientName: clientName
  }
}];

// Check if the user approved or rejected
const webhookData = $input.first().json;
const action = (webhookData.query && webhookData.query.action) || 'reject';

if (action !== 'approve') {
  // Rejected - return empty array to stop the pipeline
  // (no items = nothing flows to GPT-4o)
  return [];
}

// Approved - retrieve original matched items from Confidence Gate
const originalItems = $('Confidence Gate').all();
return originalItems;

// Parse OpenAI API response and extract slide content
const items = [];
const allPrev = $('Confidence Gate').all();

for (let i = 0; i < $input.all().length; i++) {
  const response = $input.all()[i].json;
  const content = response.choices?.[0]?.message?.content || '{}';

  // Clean markdown code fences if present
  let cleaned = content.trim();
  if (cleaned.startsWith('```')) {
    cleaned = cleaned.replace(/^```(?:json)?\\n?/, '').replace(/\\n?```$/, '').trim();
  }

  let parsed;
  try {
    parsed = JSON.parse(cleaned);
  } catch (e) {
    parsed = {
      slide_title: 'Product Recommendation',
      recommendation: cleaned,
      specs: []
    };
  }

  // Carry forward the original product data (match by index)
  const prev = (allPrev[i] || allPrev[0] || {}).json || {};

  items.push({
    json: {
      slide_title: parsed.slide_title || 'Product Recommendation',
      recommendation: parsed.recommendation || '',
      specs: parsed.specs || [],
      product_name: prev.product_name || '',
      brand: prev.brand || '',
      image_url: prev.image_url || '',
      rfp_image_url: prev.rfp_image_url || '',
      confidence: prev.confidence || 0,
      quantity: prev.quantity || '',
      location: prev.location || '',
      client_name: prev.client_name || 'Client'
    }
  });
}

return items;

// Collect all parsed GPT slide items into a single array for PPTX generation
const items = $input.all();
const clientName = items[0]?.json?.client_name || 'Client';

const slides = items.map(item => ({
  slide_title: item.json.slide_title || 'Product Recommendation',
  recommendation: item.json.recommendation || '',
  specs: item.json.specs || [],
  product_name: item.json.product_name || '',
  brand: item.json.brand || '',
  image_url: item.json.image_url || '',
  rfp_image_url: item.json.rfp_image_url || '',
  confidence: item.json.confidence || 0,
  quantity: item.json.quantity || '',
  location: item.json.location || ''
}));

return [{
  json: {
    clientName: clientName,
    slides: slides
  }
}];

// Collect all low-confidence or unmatched items into a review summary
const items = $input.all();
const clientName = items[0]?.json?.client_name || 'Client';

const lines = items.map(item => {
  const d = item.json;
  const confPct = d.confidence ? (d.confidence * 100).toFixed(0) + '%' : '0%';
  const src = d.match_source === 'image' ? ' [IMG]' : '';
  let closest = '';
  if (d.product_name && d.product_name !== 'No match found') {
    closest = `\n    Closest: ${d.product_name} (${d.brand}) \u2014 ${confPct}${src}`;
    if (d.source_url) {
      closest += `\n    \uD83D\uDD17 <a href=\"${d.source_url}\">View Product</a>`;
    }
  }
  return `\u2022 Line ${d.rfp_line}: \"${d.query}\" (Qty: ${d.quantity})${closest}`;
}).join('\n\n');

const imgInfo = items[0]?.json?.images_extracted ? `\n<b>Images Analyzed:</b> ${items[0].json.images_extracted}` : '';

const message = `\u26A0\uFE0F <b>RFP Image Review Required</b>\n\n<b>Client:</b> ${clientName}\n<b>Items Below Threshold:</b> ${items.length}${imgInfo}\n\nThe following items need manual review:\n\n${lines}\n\nPlease verify and select suitable products.\n\n\u2014 Sent automatically from <b>superCXO</b>`;

return [{
  json: {
    message: message,
    count: items.length,
    client_name: clientName
  }
}];
